      const batch = writeBatch(db);
      snapMatrixDocs.docs.forEach(d => {
          const newAssignees = (d.data().assignees || []).map((id: string) => id === oldId ? newId : id);
          batch.update(d.ref, { assignees: newAssignees });
      });
      await batch.commit();
  }
};

export const HistoryService = {
